const parallax=e=>{if(window?.innerWidth>768){document.querySelectorAll(".parallax__el").forEach((t=>{const n=t?.getAttribute("size")??30,i=e.clientX,s=e.clientY,a=(window.innerWidth-i)/n,r=(window.innerHeight-s)/n;t.classList?.contains("aos-init")?(t.getAttribute("loaded")||setTimeout((()=>{t.setAttribute("loaded",!0)}),400),t.classList?.contains("aos-animate")&&t.getAttribute("loaded")&&(t.style.transition=".1s ease",t.style.transform=`translateX(${a}px) translateY(${r}px)`)):(t.style.transition=".1s ease",t.style.transform=`translateX(${a}px) translateY(${r}px)`)}))}},swiper=new Swiper(".our-technics__swiper",{direction:"horizontal",slidesPerView:1,speed:400,animations:!1,loop:!1,effect:"creative",creativeEffect:{prev:{shadow:!0,translate:["-20%",0,-1]},next:{translate:["100%",0,0]}},navigation:{nextEl:".swiper-button--next",prevEl:".swiper-button--prev"}});window.addEventListener("mousemove",parallax);const navMenu=document.querySelector(".nav-menu"),menuLinks=navMenu.querySelectorAll("li a"),closeMenu=()=>{burgerButton.classList.remove("_active"),navMenu.classList.remove("_active")},toggleMenu=()=>{for(l of(window.innerWidth<=1024&&(burgerButton.classList.toggle("_active"),navMenu.classList.toggle("_active")),menuLinks))navMenu.classList.contains("_active")?l.addEventListener("click",closeMenu):l.removeEventListener("click",closeMenu)},burgerButton=document.getElementById("burgerButton");burgerButton.addEventListener("click",toggleMenu);